const payload =
  typeof $json.body === 'string'
    ? JSON.parse($json.body)
    : $json.body;

const match = payload.doc_url.match(/\/documents\/(\d+)\/?/);

if (!match) {
  throw new Error('Dokument-ID wurde in doc_url nicht gefunden');
}

return [{
  json: {
    ...payload,
    document_id: Number(match[1]),
  },
}];

const document =
  $('Dokumentdaten und Datei zusammenführen').first().json;

return $input.all().map((item, index) => {
  const fileName =
    item.binary?.data?.fileName ??
    `page-${index + 1}.png`;

  const match = fileName.match(/page-(\d+)\.png$/i);

  return {
    json: {
      document_id: document.id,
      title: document.title ?? '',
      original_file_name:
        document.original_file_name ??
        document.filename ??
        '',

      original_content:
        document.content ?? '',

      original_custom_fields:
        Array.isArray(document.custom_fields)
          ? document.custom_fields
          : [],

      page_number:
        match
          ? Number(match[1])
          : index + 1,

      page_file_name: fileName,
    },

    binary: item.binary,
  };
});

const page =
  $('Seiten einzeln verarbeiten').item.json;

return {
  json: {
    ...page,
    image_base64: $json.image_base64,
  },
};

/**
 * Extrahiert einzelne vollständige JSON-Objekte.
 */
function extractJsonObjects(text) {
  const results = [];

  let start = -1;
  let depth = 0;
  let inString = false;
  let escaped = false;

  for (let index = 0; index < text.length; index++) {
    const char = text[index];

    if (inString) {
      if (escaped) {
        escaped = false;
        continue;
      }

      if (char === '\\') {
        escaped = true;
        continue;
      }

      if (char === '"') {
        inString = false;
      }

      continue;
    }

    if (char === '"') {
      inString = true;
      continue;
    }

    if (char === '{') {
      if (depth === 0) {
        start = index;
      }

      depth++;
      continue;
    }

    if (char === '}') {
      depth--;

      if (
        depth === 0 &&
        start >= 0
      ) {
        results.push(
          text.slice(
            start,
            index + 1
          )
        );

        start = -1;
      }
    }
  }

  return results;
}

/**
 * Repariert ungültige Backslashes in Modellantworten.
 */
function repairInvalidJsonEscapes(value) {
  return value.replace(
    /\\(?!["\\/bfnrtu])/g,
    '\\\\'
  );
}

function parseModelResult(value) {
  const raw =
    String(value ?? '').trim();

  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  const candidates = [];

  /*
   * Zuerst jeden einzelnen Markdown-Codeblock prüfen.
   * So wird bei mehrfach ausgegebenem JSON nur ein Block
   * verwendet.
   */
  const fencedPattern =
    /```(?:json)?\s*([\s\S]*?)```/gi;

  for (
    const match of raw.matchAll(
      fencedPattern
    )
  ) {
    if (match[1]?.trim()) {
      candidates.push(
        match[1].trim()
      );
    }
  }

  /*
   * Danach einzelne vollständige JSON-Objekte suchen.
   */
  candidates.push(
    ...extractJsonObjects(cleaned)
  );

  /*
   * Zum Schluss den gesamten bereinigten Inhalt prüfen.
   */
  candidates.push(cleaned);

  const checked = new Set();

  for (const candidate of candidates) {
    const trimmed =
      String(candidate ?? '').trim();

    if (
      !trimmed ||
      checked.has(trimmed)
    ) {
      continue;
    }

    checked.add(trimmed);

    const variants = [
      trimmed,
      repairInvalidJsonEscapes(trimmed),
    ];

    for (const variant of variants) {
      try {
        const parsed =
          JSON.parse(variant);

        return {
          parsed: true,
          data: parsed,
          raw,
        };
      } catch {
        // Nächste Variante prüfen.
      }
    }
  }

  return {
    parsed: false,
    data: {},
    raw,
  };
}

const pageInput =
  $('Base64-Metadaten ergänzen').item.json;

const ai =
  parseModelResult(
    $json.message?.content
  );

return {
  json: {
    document_id:
      pageInput.document_id,

    title:
      pageInput.title,

    original_file_name:
      pageInput.original_file_name,

    original_content:
      pageInput.original_content,

    original_custom_fields:
      pageInput.original_custom_fields,

    page_number:
      pageInput.page_number,

    page_file_name:
      pageInput.page_file_name,

    ai_parsed:
      ai.parsed,

    ai:
      ai.data,

    // Vorläufig für die Fehlersuche behalten.
    ai_raw:
      ai.raw,
  },
};

const pages = $input
  .all()
  .map(item => item.json)
  .sort(
    (a, b) =>
      Number(a.page_number) -
      Number(b.page_number)
  );

function toArray(value) {
  if (!Array.isArray(value)) {
    return [];
  }

  return value.filter(item =>
    item !== null &&
    item !== undefined &&
    (
      typeof item !== 'string' ||
      item.trim() !== ''
    )
  );
}

/**
 * Verhindert, dass bei einer erneuten Verarbeitung
 * bereits erzeugter KI-Inhalt als ursprünglicher
 * Paperless-OCR-Inhalt übernommen wird.
 */
function extractOriginalPaperlessContent(content) {
  const value =
    String(content ?? '').trim();

  const marker =
    '=== Ursprünglicher Paperless-OCR-Inhalt ===';

  if (!value.includes(marker)) {
    return value;
  }

  return value
    .split(marker)
    .slice(1)
    .join(marker)
    .trim();
}

const symbolNames = {
  '❤️': 'Herz',
  '❤': 'Herz',
  '♥': 'Herz',
  '♡': 'Herz',

  '△': 'Dreieck',
  '▲': 'Dreieck',
  '▽': 'Dreieck',
  '▼': 'Dreieck',

  '□': 'Quadrat',
  '■': 'Quadrat',
  '□×': 'Quadrat mit Kreuz',
  '☒': 'Quadrat mit Kreuz',
  '⊠': 'Quadrat mit Kreuz',

  '○': 'Kreis',
  '◯': 'Kreis',
  '●': 'Kreis',

  '×': 'Kreuz',
  '✕': 'Kreuz',
  '✖': 'Kreuz',

  '✓': 'Häkchen',
  '✔': 'Häkchen',

  '→': 'Pfeil nach rechts',
  '←': 'Pfeil nach links',
  '↑': 'Pfeil nach oben',
  '↓': 'Pfeil nach unten',
};

/**
 * Vereinheitlicht String- und Objektantworten.
 */
function normalizeVisualItem(value, fallbackType) {
  if (
    value === null ||
    value === undefined
  ) {
    return null;
  }

  if (typeof value === 'string') {
    const raw = value.trim();

    if (!raw) {
      return null;
    }

    return {
      type: fallbackType,
      label:
        symbolNames[raw] ??
        raw,
      symbol:
        symbolNames[raw]
          ? raw
          : '',
      text: '',
      state: '',
      description: '',
    };
  }

  if (typeof value !== 'object') {
    return null;
  }

  return {
    type:
      String(
        value.type ??
        fallbackType
      ).trim(),

    label:
      String(
        value.label ??
        value.name ??
        ''
      ).trim(),

    symbol:
      String(
        value.symbol ??
        value.emoji ??
        value.glyph ??
        ''
      ).trim(),

    text:
      String(
        value.text ??
        value.transcription ??
        ''
      ).trim(),

    state:
      String(
        value.state ??
        ''
      ).trim(),

    description:
      String(
        value.description ??
        value.details ??
        ''
      ).trim(),
  };
}

function formatSymbol(value) {
  const item =
    normalizeVisualItem(
      value,
      'symbol'
    );

  if (!item) {
    return null;
  }

  const label =
    item.label ||
    symbolNames[item.symbol] ||
    'Unbekanntes Symbol';

  const parts = [label];

  if (item.symbol) {
    parts.push(
      `(Symbol: ${item.symbol})`
    );
  }

  if (item.description) {
    parts.push(
      `– ${item.description}`
    );
  }

  return parts.join(' ');
}

function formatCheckbox(value) {
  const item =
    normalizeVisualItem(
      value,
      'checkbox'
    );

  if (!item) {
    return null;
  }

  const stateNames = {
    checked: 'angekreuzt',
    unchecked: 'nicht angekreuzt',
    unclear: 'Status unklar',
  };

  const label =
    item.label ||
    'Kontrollkästchen ohne lesbare Beschriftung';

  const state =
    stateNames[item.state] ??
    'Status unklar';

  const result =
    `${label} (Kontrollkästchen: ${state})`;

  return item.description
    ? `${result} – ${item.description}`
    : result;
}

function formatHandwriting(value) {
  const item =
    normalizeVisualItem(
      value,
      'handwriting'
    );

  if (!item) {
    return null;
  }

  const text =
    item.text ||
    item.label ||
    item.description;

  if (!text) {
    return null;
  }

  const result =
    `${text} (handgeschriebener Text)`;

  if (
    item.description &&
    item.description !== text
  ) {
    return (
      `${result} – ` +
      item.description
    );
  }

  return result;
}

function formatVisualObject(
  value,
  fallbackType,
  typeLabel,
  includeDetectedType = false
) {
  const item =
    normalizeVisualItem(
      value,
      fallbackType
    );

  if (!item) {
    return null;
  }

  const mainText =
    item.label ||
    item.text ||
    typeLabel;

  const details = [];

  if (
    item.text &&
    item.text !== mainText
  ) {
    details.push(
      `Text: ${item.text}`
    );
  }

  if (
    includeDetectedType &&
    item.type &&
    item.type !== fallbackType
  ) {
    details.push(
      `Typ: ${item.type}`
    );
  }

  if (item.description) {
    details.push(
      item.description
    );
  }

  if (item.symbol) {
    details.push(
      `Symbol: ${item.symbol}`
    );
  }

  if (details.length === 0) {
    return `${mainText} (${typeLabel})`;
  }

  return (
    `${mainText} (${typeLabel}: ` +
    `${details.join('; ')})`
  );
}

const textParts = [];
const tables = [];
const documentStructures = [];
const searchableVisualSections = [];
const warnings = [];

for (const page of pages) {
  const ai =
    page.ai ?? {};

  const aiText =
    ai.text_markdown ||
    ai.text ||
    (
      !page.ai_parsed
        ? page.ai_raw
        : ''
    );

  if (String(aiText ?? '').trim()) {
    textParts.push(
      `## Seite ${page.page_number}\n\n` +
      String(aiText).trim()
    );
  }

  for (
    const table of toArray(
      ai.tables_markdown
    )
  ) {
    tables.push(
      `### Tabelle auf Seite ${page.page_number}\n\n` +
      String(table).trim()
    );
  }

  const structures =
    toArray(
      ai.document_structure
    );

  if (structures.length > 0) {
    documentStructures.push(
      `### Struktur auf Seite ${page.page_number}\n\n` +
      structures
        .map(value => `- ${value}`)
        .join('\n')
    );
  }

  const pageVisualEntries = [];

  /*
   * Symbole, Logos und geometrische Formen
   */
  for (
    const value of toArray(
      ai.symbols
    )
  ) {
    const formatted =
      formatSymbol(value);

    if (formatted) {
      pageVisualEntries.push(
        formatted
      );
    }
  }

  /*
   * Kontrollkästchen
   */
  for (
    const value of toArray(
      ai.checkboxes
    )
  ) {
    const formatted =
      formatCheckbox(value);

    if (formatted) {
      pageVisualEntries.push(
        formatted
      );
    }
  }

  /*
   * Handschriftliche Texte
   */
  for (
    const value of toArray(
      ai.handwriting
    )
  ) {
    const formatted =
      formatHandwriting(value);

    if (formatted) {
      pageVisualEntries.push(
        formatted
      );
    }
  }

  /*
   * Stempel
   */
  for (
    const value of toArray(
      ai.stamps
    )
  ) {
    const formatted =
      formatVisualObject(
        value,
        'stamp',
        'Stempel'
      );

    if (formatted) {
      pageVisualEntries.push(
        formatted
      );
    }
  }

  /*
   * Unterschriften
   */
  for (
    const value of toArray(
      ai.signatures
    )
  ) {
    const formatted =
      formatVisualObject(
        value,
        'signature',
        'Unterschrift'
      );

    if (formatted) {
      pageVisualEntries.push(
        formatted
      );
    }
  }

  /*
   * Fotos und Bilder
   */
  for (
    const value of toArray(
      ai.images
    )
  ) {
    const formatted =
      formatVisualObject(
        value,
        'image',
        'Bild oder Foto'
      );

    if (formatted) {
      pageVisualEntries.push(
        formatted
      );
    }
  }

  /*
   * Diagramme, Schaubilder und Abbildungen
   */
  for (
    const value of toArray(
      ai.figures
    )
  ) {
    const formatted =
      formatVisualObject(
        value,
        'figure',
        'Diagramm oder Abbildung',
        true
      );

    if (formatted) {
      pageVisualEntries.push(
        formatted
      );
    }
  }

  /*
   * Markierungen und weitere visuelle Hinweise
   */
  for (
    const value of toArray(
      ai.visual_notes
    )
  ) {
    const formatted =
      formatVisualObject(
        value,
        'visual_note',
        'visueller Hinweis'
      );

    if (formatted) {
      pageVisualEntries.push(
        formatted
      );
    }
  }

  if (pageVisualEntries.length > 0) {
    searchableVisualSections.push(
      `## Seite ${page.page_number}\n\n` +
      pageVisualEntries
        .map(
          (value, index) =>
            `${index + 1}. ${value}`
        )
        .join('\n\n')
    );
  }

  for (
    const warning of toArray(
      ai.warnings
    )
  ) {
    warnings.push(
      `Seite ${page.page_number}: ${warning}`
    );
  }
}

const aiSections = [];

if (textParts.length > 0) {
  aiSections.push(
    `# Dokumenttext\n\n` +
    textParts.join('\n\n')
  );
}

if (tables.length > 0) {
  aiSections.push(
    `# Tabellen\n\n` +
    tables.join('\n\n')
  );
}

if (documentStructures.length > 0) {
  aiSections.push(
    `# Dokumentstruktur\n\n` +
    documentStructures.join('\n\n')
  );
}

if (searchableVisualSections.length > 0) {
  aiSections.push(
    `# Erkannte visuelle Elemente und handgeschriebene Texte\n\n` +
    searchableVisualSections.join('\n\n')
  );
}

/*
 * Ausschließlich neuer KI-Inhalt.
 */
const aiContent =
  aiSections
    .join('\n\n')
    .trim();

/*
 * Ursprünglicher Paperless-OCR-Inhalt.
 */
const originalPaperlessContent =
  extractOriginalPaperlessContent(
    pages[0]?.original_content
  );

const originalSection =
  originalPaperlessContent ||
  '[Kein ursprünglicher Paperless-OCR-Inhalt vorhanden]';

/*
 * Inhalt, der später nach Paperless geschrieben wird.
 */
const combinedPaperlessContent = [
  '=== KI-OCR / Vision-Ergebnis ===',
  '',
  aiContent ||
    '[Kein brauchbares KI-OCR-Ergebnis erzeugt]',
  '',
  '=== Ursprünglicher Paperless-OCR-Inhalt ===',
  '',
  originalSection,
]
  .join('\n')
  .trim();

/*
 * Qualitätsprüfung des neuen KI-Inhalts.
 */
const normalizedAiContent =
  aiContent.toLowerCase();

const contentWithoutErrorPhrases =
  normalizedAiContent
    .replace(/\[?unlesbar\]?/gi, '')
    .replace(/keine daten/gi, '')
    .replace(/nicht erkennbar/gi, '')
    .replace(/kein text erkannt/gi, '')
    .replace(/^#+.*$/gm, '')
    .replace(/\s+/g, '');

const quality = {
  usable:
    pages.length > 0 &&
    aiContent.length >= 100 &&
    contentWithoutErrorPhrases.length >= 30,

  ai_character_count:
    aiContent.length,

  original_character_count:
    originalPaperlessContent.length,

  combined_character_count:
    combinedPaperlessContent.length,

  page_count:
    pages.length,

  ai_json_valid_for_all_pages:
    pages.length > 0 &&
    pages.every(
      page =>
        page.ai_parsed === true
    ),

  markdown_table_detected:
    tables.length > 0,

  visual_descriptions_present:
    searchableVisualSections.length > 0,

  warnings,
};

return [
  {
    json: {
      document_id:
        pages[0]?.document_id,

      title:
        pages[0]?.title ?? '',

      original_file_name:
        pages[0]?.original_file_name ?? '',

      original_custom_fields:
        pages[0]?.original_custom_fields ?? [],

      pages,

      ai_content:
        aiContent,

      original_paperless_content:
        originalPaperlessContent,

      combined_paperless_content:
        combinedPaperlessContent,

      quality,

      write_back: true,
    },
  },
];

const fieldId = 1;

const customFields =
  Array.isArray($json.custom_fields)
    ? $json.custom_fields
    : [];

const processedField =
  customFields.find(
    field => Number(field.field) === fieldId
  );

return {
  json: {
    ...$json,
    ki_ocr_processed:
      processedField?.value === true,
  },
};

const kiOcrFieldId = 1;

const existing =
  Array.isArray($json.original_custom_fields)
    ? $json.original_custom_fields.map(item => ({ ...item }))
    : [];

const updated = existing.filter(
  item => Number(item.field) !== kiOcrFieldId
);

updated.push({
  field: kiOcrFieldId,
  value: true,
});

return {
  json: {
    ...$json,
    updated_custom_fields: updated,
  },
};

